  ('elementary-8b44517b-moex-00737', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '某法律規定：「本法自公布日施行。」若總統於民國110年6月1日公布該法，則該法應於何日生效？', '["6月1日", "6月2日", "6月3日", "6月4日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00738', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於我國現行中央政府體制，下列敘述何者錯誤？', '["總統對行政院院長有人事任免權", "修憲後因立法院喪失對行政院院長的同意權，行政院不再對立法院負責", "總統享有被動的國會解散權", "我國中央政府體制既不是總統制，也不是內閣制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00739', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於公法與私法之區別，下列敘述何者錯誤？', '["救濟之方式不同，公法適用行政爭訟，私法則適用民事訴訟", "強制執行之依據不同，公法適用行政執行法與行政訴訟法，私法適用強制執行法", "損害賠償管道不同，公法適用國家賠償法，私法適用民法", "勞動基準法之規範客體為私法上僱傭關係，故屬純粹的私法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00740', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何者非屬我國憲法或憲法增修條文賦予大法官之職權？', '["解釋憲法", "統一解釋法律及命令", "審理總統、副總統之罷免", "審理政黨違憲之解散"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00741', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於刑法第19條第3項之規定，下列敘述何者錯誤？', '["學理上稱之為原因自由行為", "本項須行為人在實際實行犯罪時具備完全行為責任能力狀況", "現行立法模式，在學理上有稱為例外模式", "本項須行為人因故意或過失自行招致無責任能力或限制責任能力狀況"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00742', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何者是憲法最高性的直接展現？', '["行政院之施政不得牴觸立法院三讀通過，總統公布之法律", "法院之判決，不得不適用法規或適用不當", "立法院通過之法律，不得牴觸憲法", "行政機關之管轄權，不得違反其組織法規，非依法規不得設定或變更"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00743', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依司法院大法官解釋，有關自由民主憲政秩序，下列敘述何者錯誤？', '["係指憲法中具有本質之重要性而為規範秩序存立之基礎者", "憲法增修條文如與憲法中具有本質重要性之規範相衝突，依後法優於前法之原則，增修條文之效力優先", "其內涵包括憲法規定之民主共和國原則與國民主權原則", "凡憲法設置之機關，均有遵守自由民主憲政秩序之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00744', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依憲法及公民投票法規定，有關我國公民投票制度，下列敘述何者正確？', '["是憲法上依法行政原則的實現", "因為是對事、而非對人的投票，所以普通、平等、直接之投票方法不適用", "現行制度不只有全國性，也有地方性之公民投票", "為確實監督國家政策之落實，得針對預算與人事事項提案發起公民投票"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00745', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '有關比例原則之敘述，下列何者錯誤？', '["須採取之方法應有助於目的之達成", "多種同樣達成目的之方法中，須採取對人民權益損害最少者", "須採取之方法所造成之損害不得與欲達成目的之利益顯失均衡", "一行為違反數行政法上義務，應採取最輕之處罰規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00746', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列事項，何者不適用我國行政程序法之程序規定？', '["外交部與外國之建交行為", "撤銷進出口廠商營業登記之行為", "廢止土地徵收之行為", "再生能源發電設備生產電能躉購費率之審定行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
